solution_code:
#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
int main(void) {
    printf("Step 1: stderr active\n");
    int saved_stderr = dup(STDERR_FILENO);
    int devnull = open("/dev/null", O_WRONLY);
    dup2(devnull, STDERR_FILENO);
    close(devnull);
    fprintf(stderr, "This should be suppressed\n");
    printf("Step 2: stderr suppressed\n");
    dup2(saved_stderr, STDERR_FILENO);
    close(saved_stderr);
    printf("Step 3: stderr restored\n");
    return 0;
}

